import jsonimport socketfrom Searcher import screamimport timeHOST = socket.gethostbyname(socket.gethostname())PORT = 8080devices = []server = socket.socket(socket.AF_INET, socket.SOCK_STREAM)server.setblocking(False)server.bind((HOST, PORT))server.listen()while True:    try:        conn, adr = server.accept()        print("Connected by", adr)        conn.setblocking(True)        break    except:        scream()        time.sleep(2)def recvall(conn, length):    data = bytearray()    while len(data) < length:        packet = conn.recv(length - len(data))        if not packet:            return None        data.extend(packet)    return bytes(data)def recv_message(connl, l = 4):    raw_msglen = recvall(conn, l)    if not raw_msglen:        return None    msglen = int.from_bytes(raw_msglen, byteorder='big')    return recvall(conn, msglen)received_data = json.loads(recv_message(conn).decode('utf-8'))received_bytes = 0chunk_size = 8192file_size = received_data['size']file_name = received_data['name']with open(file_name, 'wb') as f:    while received_bytes < file_size:        remaining = file_size - received_bytes        to_read = min(remaining, chunk_size)        chunk = conn.recv(to_read)        if not chunk:            print("Connection closed")            break        f.write(chunk)        received_bytes += len(chunk)# print(data)